# -----------------------------
# Data classes
# -----------------------------

@dataclass
class Detection:
    dictionary_name: str
    marker_id: int
    corners: np.ndarray


@dataclass
class Track:
    dictionary_name: str
    marker_id: int
    corners: np.ndarray
    misses: int = 0
    seen_count: int = 1
    last_seen_frame: int = 0

    @property
    def key(self) -> Tuple[str, int]:
        return (self.dictionary_name, self.marker_id)


@dataclass
class Stroke:
    color: Tuple[int, int, int]
    size: int
    points: List[Tuple[float, float]] = field(default_factory=list)


@dataclass
class Action:
    action_type: str
    key: Optional[Tuple[str, int]]
    data: object = None


