# -----------------------------
# OpenCV ArUco compatibility
# -----------------------------

def require_aruco() -> None:
    if not hasattr(cv2, "aruco"):
        raise RuntimeError(
            "Your OpenCV install has no cv2.aruco module. Install it with:\n"
            "python -m pip uninstall opencv-python opencv-contrib-python -y\n"
            "python -m pip install opencv-contrib-python numpy"
        )


def get_dictionary_id(name: str) -> int:
    if not hasattr(cv2.aruco, name):
        raise RuntimeError(f"This OpenCV version does not support {name}.")
    return getattr(cv2.aruco, name)


def create_detector_parameters():
    if hasattr(cv2.aruco, "DetectorParameters"):
        params = cv2.aruco.DetectorParameters()
    else:
        params = cv2.aruco.DetectorParameters_create()

    for attr, value in [
        ("adaptiveThreshWinSizeMin", 3),
        ("adaptiveThreshWinSizeMax", 45),
        ("adaptiveThreshWinSizeStep", 4),
        ("adaptiveThreshConstant", 7),
        ("minMarkerPerimeterRate", 0.02),
        ("maxMarkerPerimeterRate", 4.0),
        ("polygonalApproxAccuracyRate", 0.035),
        ("minCornerDistanceRate", 0.04),
        ("minDistanceToBorder", 2),
        ("cornerRefinementWinSize", 5),
        ("cornerRefinementMaxIterations", 40),
        ("cornerRefinementMinAccuracy", 0.03),
        ("errorCorrectionRate", 0.65),
    ]:
        if hasattr(params, attr):
            setattr(params, attr, value)

    if hasattr(cv2.aruco, "CORNER_REFINE_SUBPIX") and hasattr(params, "cornerRefinementMethod"):
        params.cornerRefinementMethod = cv2.aruco.CORNER_REFINE_SUBPIX

    if hasattr(params, "detectInvertedMarker"):
        params.detectInvertedMarker = True

    return params


def get_predefined_dictionary(name: str):
    dict_id = get_dictionary_id(name)
    if hasattr(cv2.aruco, "getPredefinedDictionary"):
        return cv2.aruco.getPredefinedDictionary(dict_id)
    return cv2.aruco.Dictionary_get(dict_id)


class ArucoDetectorWrapper:
    def __init__(self, dictionary_name: str):
        self.dictionary_name = dictionary_name
        self.dictionary = get_predefined_dictionary(dictionary_name)
        self.parameters = create_detector_parameters()
        self.new_api = hasattr(cv2.aruco, "ArucoDetector")
        self.detector = None
        if self.new_api:
            self.detector = cv2.aruco.ArucoDetector(self.dictionary, self.parameters)

    def detect(self, image: np.ndarray) -> Tuple[List[np.ndarray], Optional[np.ndarray]]:
        if self.new_api and self.detector is not None:
            corners, ids, _rejected = self.detector.detectMarkers(image)
        else:
            corners, ids, _rejected = cv2.aruco.detectMarkers(
                image, self.dictionary, parameters=self.parameters
            )
        return corners, ids


def build_detectors() -> Dict[str, ArucoDetectorWrapper]:
    names = AUTO_DICT_ORDER if DICTIONARY_NAME == "AUTO" else [DICTIONARY_NAME]
    return {name: ArucoDetectorWrapper(name) for name in names}


# -----------------------------
# Marker detection and tracking
# -----------------------------

def prepare_frames_for_detection(frame: np.ndarray) -> List[np.ndarray]:
    gray = cv2.cvtColor(frame, cv2.COLOR_BGR2GRAY)
    frames = [gray]

    if ENHANCE_CONTRAST:
        clahe = cv2.createCLAHE(clipLimit=2.0, tileGridSize=(8, 8))
        enhanced = clahe.apply(gray)
        frames.append(enhanced)

    return frames


def detect_markers(frame: np.ndarray, detectors: Dict[str, ArucoDetectorWrapper]) -> List[Detection]:
    global locked_dictionary, dictionary_hit_counts

    detection_frames = prepare_frames_for_detection(frame)

    if DICTIONARY_NAME != "AUTO":
        names_to_try = [DICTIONARY_NAME]
    elif locked_dictionary is not None:
        names_to_try = [locked_dictionary]
    else:
        names_to_try = AUTO_DICT_ORDER

    best_name: Optional[str] = None
    best_corners: Optional[List[np.ndarray]] = None
    best_ids: Optional[np.ndarray] = None
    best_count = 0

    # Try both normal grayscale and enhanced grayscale.
    # This improves recognition on uneven lighting without making tracking slow.
    for detect_frame in detection_frames:
        for name in names_to_try:
            detector = detectors.get(name)
            if detector is None:
                continue

            corners, ids = detector.detect(detect_frame)
            if ids is None or len(ids) == 0:
                continue

            ids_flat = ids.flatten().astype(int)
            if CUBE_FACE_IDS is not None:
                keep_indices = [i for i, marker_id in enumerate(ids_flat) if int(marker_id) in CUBE_FACE_IDS]
                if not keep_indices:
                    continue
                corners = [corners[i] for i in keep_indices]
                ids_flat = np.array([ids_flat[i] for i in keep_indices], dtype=int)

            count = len(ids_flat)
            if count > best_count:
                best_name = name
                best_corners = corners
                best_ids = ids_flat
                best_count = count

    if best_name is None or best_corners is None or best_ids is None:
        return []

    if DICTIONARY_NAME == "AUTO" and locked_dictionary is None:
        dictionary_hit_counts[best_name] = dictionary_hit_counts.get(best_name, 0) + 1
        if dictionary_hit_counts[best_name] >= AUTO_LOCK_AFTER_HITS:
            locked_dictionary = best_name
            print(f"Locked ArUco dictionary: {locked_dictionary}")

    detections: List[Detection] = []
    for corner_item, marker_id in zip(best_corners, best_ids):
        corners = np.asarray(corner_item, dtype=np.float32).reshape(4, 2)
        detections.append(Detection(best_name, int(marker_id), corners))

    return detections



def polygon_area(points: np.ndarray) -> float:
    x = points[:, 0]
    y = points[:, 1]
    return float(0.5 * abs(np.dot(x, np.roll(y, 1)) - np.dot(y, np.roll(x, 1))))


def update_tracks(detections: List[Detection], frame_index: int) -> None:
    for track in tracks.values():
        track.misses += 1

    for det in detections:
        key = (det.dictionary_name, det.marker_id)
        if key in tracks:
            old = tracks[key]
            old.corners = (
                CORNER_SMOOTHING * det.corners +
                (1.0 - CORNER_SMOOTHING) * old.corners
            ).astype(np.float32)
            old.misses = 0
            old.seen_count += 1
            old.last_seen_frame = frame_index
        else:
            tracks[key] = Track(det.dictionary_name, det.marker_id, det.corners.astype(np.float32), 0, 1, frame_index)

    old_keys = [key for key, track in tracks.items() if track.misses > TRACK_PERSIST_FRAMES]
    for key in old_keys:
        tracks.pop(key, None)


def visible_tracks() -> List[Track]:
    return [track for track in tracks.values() if track.misses <= TRACK_PERSIST_FRAMES]


def track_is_drawable(track: Track) -> bool:
    if track.seen_count < MIN_SEEN_COUNT_FOR_DRAW:
        return False
    if DRAW_ONLY_ON_FRESH_MARKERS and track.misses > 0:
        return False
    return True


# -----------------------------
# Geometry
# -----------------------------

def homography_from_corners(corners: np.ndarray) -> Tuple[Optional[np.ndarray], Optional[np.ndarray]]:
    src = np.array([[0, 0], [1, 0], [1, 1], [0, 1]], dtype=np.float32)
    dst = corners.astype(np.float32)
    H = cv2.getPerspectiveTransform(src, dst)
    H_inv = cv2.getPerspectiveTransform(dst, src)
    return H, H_inv


def transform_point(H: np.ndarray, u: float, v: float) -> Tuple[float, float]:
    p = np.array([u, v, 1.0], dtype=np.float64)
    r = H.astype(np.float64) @ p
    if abs(r[2]) < 1e-9:
        return 0.0, 0.0
    return float(r[0] / r[2]), float(r[1] / r[2])


def image_to_marker_uv(track: Track, x: float, y: float) -> Optional[Tuple[float, float]]:
    _H, H_inv = homography_from_corners(track.corners)
    if H_inv is None:
        return None
    return transform_point(H_inv, x, y)


def marker_uv_to_plane_uv(marker_u: float, marker_v: float) -> Tuple[float, float]:
    return 0.5 + (marker_u - 0.5) / plane_scale, 0.5 + (marker_v - 0.5) / plane_scale


def plane_uv_to_marker_uv(plane_u: float, plane_v: float) -> Tuple[float, float]:
    return 0.5 + (plane_u - 0.5) * plane_scale, 0.5 + (plane_v - 0.5) * plane_scale


def project_plane_point(track: Track, plane_u: float, plane_v: float) -> Tuple[int, int]:
    H, _ = homography_from_corners(track.corners)
    marker_u, marker_v = plane_uv_to_marker_uv(plane_u, plane_v)
    x, y = transform_point(H, marker_u, marker_v)
    return int(round(x)), int(round(y))


def plane_polygon(track: Track) -> np.ndarray:
    points = [
        project_plane_point(track, 0, 0),
        project_plane_point(track, 1, 0),
        project_plane_point(track, 1, 1),
        project_plane_point(track, 0, 1),
    ]
    return np.array(points, dtype=np.int32)


def marker_polygon(track: Track) -> np.ndarray:
    return np.round(track.corners).astype(np.int32)


def find_track_under_mouse(x: int, y: int, require_drawable: bool = True) -> Optional[Tuple[str, int]]:
    best_key = None
    best_area = -1.0

    for track in visible_tracks():
        if require_drawable and not track_is_drawable(track):
            continue

        marker_uv = image_to_marker_uv(track, x, y)
        if marker_uv is None:
            continue

        plane_u, plane_v = marker_uv_to_plane_uv(marker_uv[0], marker_uv[1])
        if -0.08 <= plane_u <= 1.08 and -0.08 <= plane_v <= 1.08:
            area = polygon_area(track.corners)
            if area > best_area:
                best_area = area
                best_key = track.key

    return best_key



def get_or_create_strokes(key: Tuple[str, int]) -> List[Stroke]:
    if key not in strokes_by_marker:
        strokes_by_marker[key] = []
    return strokes_by_marker[key]


def record_action(action_type: str, key: Optional[Tuple[str, int]], data: object = None) -> None:
    action_history.append(Action(action_type=action_type, key=key, data=data))


def apply_texture_to_key(key: Tuple[str, int], texture_name: str, record: bool = True) -> None:
    old_texture = textures_by_marker.get(key)
    textures_by_marker[key] = texture_name
    if record:
        record_action("texture", key, old_texture)
    print(f"Applied texture {texture_name} to marker {key}")


def remove_texture_from_key(key: Tuple[str, int], record: bool = True) -> None:
    old_texture = textures_by_marker.get(key)
    if old_texture is not None:
        textures_by_marker.pop(key, None)
        if record:
            record_action("texture", key, old_texture)
        print(f"Removed texture from marker {key}")


def apply_key_with_color(key: Tuple[str, int], color: Tuple[int, int, int], record: bool = True) -> None:
    old_fill = fills_by_marker.get(key)
    fills_by_marker[key] = (color, FILL_ALPHA)
    if record:
        record_action("fill", key, old_fill)
    print(f"Filled marker {key} with {current_color_name}")


def clear_key(key: Tuple[str, int], record: bool = True) -> None:
    old_strokes = [Stroke(s.color, s.size, list(s.points)) for s in strokes_by_marker.get(key, [])]
    old_fill = fills_by_marker.get(key)
    old_texture = textures_by_marker.get(key)

    strokes_by_marker[key] = []
    fills_by_marker.pop(key, None)
    textures_by_marker.pop(key, None)

    if record:
        record_action("clear_face", key, {
            "strokes": old_strokes,
            "fill": old_fill,
            "texture": old_texture,
        })

    reset_pending_first_point()
    print(f"Cleared marker {key}")


def clear_everything(record: bool = True) -> None:
    old_strokes = {
        key: [Stroke(s.color, s.size, list(s.points)) for s in strokes]
        for key, strokes in strokes_by_marker.items()
    }
    old_fills = dict(fills_by_marker)
    old_textures = dict(textures_by_marker)

    strokes_by_marker.clear()
    fills_by_marker.clear()
    textures_by_marker.clear()

    if record:
        record_action("clear_all", None, {
            "strokes": old_strokes,
            "fills": old_fills,
            "textures": old_textures,
        })

    reset_pending_first_point()
    print("Cleared all faces")


def undo_last_action() -> None:
    if not action_history:
        print("Nothing to undo.")
        return

    action = action_history.pop()
    key = action.key

    if action.action_type == "stroke":
        if key is not None and key in strokes_by_marker and strokes_by_marker[key]:
            strokes_by_marker[key].pop()
            print(f"Undid last stroke on marker {key}")
        return

    if action.action_type == "erase":
        if key is not None:
            old_strokes = action.data
            if isinstance(old_strokes, list):
                strokes_by_marker[key] = [Stroke(s.color, s.size, list(s.points)) for s in old_strokes]
                print(f"Undid eraser on marker {key}")
        return

    if action.action_type == "texture":
        if key is not None:
            old_texture = action.data
            if old_texture is None:
                textures_by_marker.pop(key, None)
            else:
                textures_by_marker[key] = str(old_texture)
            print(f"Undid texture change on marker {key}")
        return

    if action.action_type == "fill":
        if key is not None:
            old_fill = action.data
            if old_fill is None:
                fills_by_marker.pop(key, None)
            else:
                fills_by_marker[key] = old_fill
            print(f"Undid fill change on marker {key}")
        return

    if action.action_type == "clear_face":
        if key is not None and isinstance(action.data, dict):
            strokes_by_marker[key] = [Stroke(s.color, s.size, list(s.points)) for s in action.data.get("strokes", [])]
            old_fill = action.data.get("fill")
            old_texture = action.data.get("texture")
            if old_fill is None:
                fills_by_marker.pop(key, None)
            else:
                fills_by_marker[key] = old_fill
            if old_texture is None:
                textures_by_marker.pop(key, None)
            else:
                textures_by_marker[key] = str(old_texture)
            print(f"Undid clear marker {key}")
        return

    if action.action_type == "clear_all":
        if isinstance(action.data, dict):
            strokes_by_marker.clear()
            fills_by_marker.clear()
            textures_by_marker.clear()

            old_strokes = action.data.get("strokes", {})
            for old_key, strokes in old_strokes.items():
                strokes_by_marker[old_key] = [Stroke(s.color, s.size, list(s.points)) for s in strokes]

            fills_by_marker.update(action.data.get("fills", {}))
            textures_by_marker.update(action.data.get("textures", {}))
            print("Undid clear all")
        return


def erase_at_point(key: Tuple[str, int], plane_u: float, plane_v: float) -> None:
    strokes = strokes_by_marker.get(key, [])
    if not strokes:
        return

    old_strokes = [Stroke(s.color, s.size, list(s.points)) for s in strokes]
    changed = False
    new_strokes: List[Stroke] = []

    for stroke in strokes:
        current_segment: List[Tuple[float, float]] = []

        # Size-aware erasing. Large drawn lines are a bit easier to hit.
        stroke_extra = max(0.0, stroke.size / 700.0)
        radius = ERASER_RADIUS_UV + stroke_extra

        for point_u, point_v in stroke.points:
            dist = math.hypot(point_u - plane_u, point_v - plane_v)

            if dist <= radius:
                changed = True
                if len(current_segment) >= 2:
                    new_strokes.append(Stroke(stroke.color, stroke.size, list(current_segment)))
                current_segment = []
            else:
                current_segment.append((point_u, point_v))

        if len(current_segment) >= 2:
            new_strokes.append(Stroke(stroke.color, stroke.size, list(current_segment)))
        elif len(current_segment) == 1 and len(stroke.points) == 1:
            new_strokes.append(Stroke(stroke.color, stroke.size, list(current_segment)))

    if changed:
        strokes_by_marker[key] = new_strokes
        # Record the first change in a drag; repeated erasing while mouse is down should not spam undo too much.
        if not action_history or action_history[-1].action_type != "erase" or action_history[-1].key != key or mouse_down is False:
            record_action("erase", key, old_strokes)


def erase_under_mouse(x: int, y: int) -> None:
    global active_key

    selected_key = find_track_under_mouse(x, y, require_drawable=True)
    if selected_key is None:
        return

    active_key = selected_key
    track = tracks.get(selected_key)
    if track is None:
        return

    marker_uv = image_to_marker_uv(track, x, y)
    if marker_uv is None:
        return

    plane_u, plane_v = marker_uv_to_plane_uv(marker_uv[0], marker_uv[1])
    if -0.08 <= plane_u <= 1.08 and -0.08 <= plane_v <= 1.08:
        erase_at_point(selected_key, max(0.0, min(1.0, plane_u)), max(0.0, min(1.0, plane_v)))




def reset_pending_first_point() -> None:
    global pending_first_point
    pending_first_point = None


def confirmed_first_point(key: Tuple[str, int], plane_u: float, plane_v: float, x: int, y: int) -> bool:
    """Return True only when a new first point is stable for a few frames.

    This prevents random single dots caused by one bad marker read.
    It does not affect normal tracking or existing strokes.
    """
    global pending_first_point

    if CONFIRM_FIRST_POINT_FRAMES <= 1:
        return True

    if pending_first_point is None or pending_first_point.get("key") != key:
        pending_first_point = {
            "key": key,
            "u": plane_u,
            "v": plane_v,
            "x": x,
            "y": y,
            "count": 1,
        }
        return False

    last_u = float(pending_first_point["u"])
    last_v = float(pending_first_point["v"])
    last_x = int(pending_first_point["x"])
    last_y = int(pending_first_point["y"])

    uv_distance = math.hypot(plane_u - last_u, plane_v - last_v)
    screen_distance = math.hypot(x - last_x, y - last_y)

    if uv_distance <= CONFIRM_FIRST_POINT_UV_RADIUS and screen_distance <= CONFIRM_FIRST_POINT_SCREEN_RADIUS:
        pending_first_point["u"] = (last_u + plane_u) * 0.5
        pending_first_point["v"] = (last_v + plane_v) * 0.5
        pending_first_point["x"] = int((last_x + x) * 0.5)
        pending_first_point["y"] = int((last_y + y) * 0.5)
        pending_first_point["count"] = int(pending_first_point["count"]) + 1
    else:
        # Different place: probably an unstable detection jump. Start confirmation again.
        pending_first_point = {
            "key": key,
            "u": plane_u,
            "v": plane_v,
            "x": x,
            "y": y,
            "count": 1,
        }
        return False

    return int(pending_first_point["count"]) >= CONFIRM_FIRST_POINT_FRAMES


def add_point_to_current_stroke(x: int, y: int) -> None:
    global current_stroke, active_key

    if not mouse_down:
        reset_pending_first_point()
        return

    selected_key = find_track_under_mouse(x, y, require_drawable=True)

    # If no fresh marker is under the mouse, do not add random points.
    # Tracking still follows the cube; only drawing is paused for that moment.
    if selected_key is None:
        reset_pending_first_point()
        return

    switching_face = ALLOW_CROSS_FACE_STROKES and selected_key != active_key

    if switching_face:
        active_key = selected_key
        current_stroke = None
        reset_pending_first_point()

    if active_key is None:
        active_key = selected_key

    track = tracks.get(active_key)
    if track is None or not track_is_drawable(track):
        reset_pending_first_point()
        return

    marker_uv = image_to_marker_uv(track, x, y)
    if marker_uv is None:
        reset_pending_first_point()
        return

    plane_u, plane_v = marker_uv_to_plane_uv(marker_uv[0], marker_uv[1])

    if not (-0.15 <= plane_u <= 1.15 and -0.15 <= plane_v <= 1.15):
        reset_pending_first_point()
        return

    plane_u = max(0.0, min(1.0, plane_u))
    plane_v = max(0.0, min(1.0, plane_v))

    # If the current stroke does not exist yet, do not immediately commit a dot.
    # First wait until the first point is stable for a couple frames.
    if current_stroke is None:
        if not confirmed_first_point(active_key, plane_u, plane_v, x, y):
            return

        start_u = float(pending_first_point["u"]) if pending_first_point is not None else plane_u
        start_v = float(pending_first_point["v"]) if pending_first_point is not None else plane_v

        current_stroke = Stroke(color=brush_color, size=brush_size)
        get_or_create_strokes(active_key).append(current_stroke)
        record_action("stroke", active_key, current_stroke)
        current_stroke.points.append((start_u, start_v))
        reset_pending_first_point()
        return

    reset_pending_first_point()

    if not current_stroke.points:
        # Same confirmation for an empty stroke, so a bad single frame cannot create a dot.
        if not confirmed_first_point(active_key, plane_u, plane_v, x, y):
            return

        start_u = float(pending_first_point["u"]) if pending_first_point is not None else plane_u
        start_v = float(pending_first_point["v"]) if pending_first_point is not None else plane_v
        current_stroke.points.append((start_u, start_v))
        reset_pending_first_point()
        return

    last_u, last_v = current_stroke.points[-1]
    uv_jump = math.hypot(plane_u - last_u, plane_v - last_v)

    # Important change:
    # Before, a huge same-face jump started a new stroke and still placed a point.
    # That created random dots. Now we reject the point completely.
    if REJECT_LONELY_JUMP_DOTS and uv_jump > MAX_UV_JUMP_SAME_FACE:
        return

    if uv_jump > 0.003:
        current_stroke.points.append((plane_u, plane_v))




