def make_noise_texture(base: Tuple[int, int, int], strength: int = 40, blur: int = 5) -> np.ndarray:
    rng = np.random.default_rng(12345 + int(sum(base)) + strength)
    img = np.zeros((TEXTURE_SIZE, TEXTURE_SIZE, 3), dtype=np.uint8)
    img[:, :] = np.array(base, dtype=np.uint8)
    noise = rng.normal(0, strength, img.shape).astype(np.int16)
    img = np.clip(img.astype(np.int16) + noise, 0, 255).astype(np.uint8)
    if blur > 0:
        k = blur if blur % 2 == 1 else blur + 1
        img = cv2.GaussianBlur(img, (k, k), 0)
    return img


def make_grass_texture() -> np.ndarray:
    img = make_noise_texture((45, 125, 55), 35, 5)
    rng = np.random.default_rng(7)
    for _ in range(220):
        x = int(rng.integers(0, TEXTURE_SIZE))
        y = int(rng.integers(0, TEXTURE_SIZE))
        length = int(rng.integers(12, 34))
        color = tuple(int(v) for v in rng.choice([
            (35, 160, 70), (55, 190, 80), (25, 105, 45), (80, 210, 100)
        ]))
        cv2.line(img, (x, y), (x + int(rng.integers(-5, 6)), max(0, y - length)), color, 1, cv2.LINE_AA)
    return img


def make_wood_texture() -> np.ndarray:
    y, x = np.mgrid[0:TEXTURE_SIZE, 0:TEXTURE_SIZE]
    grain = 0.5 + 0.5 * np.sin(x / 8.0 + 0.7 * np.sin(y / 18.0))
    rings = 0.5 + 0.5 * np.sin((x + y * 0.25) / 20.0)
    val = (0.65 * grain + 0.35 * rings)
    img = np.zeros((TEXTURE_SIZE, TEXTURE_SIZE, 3), dtype=np.uint8)
    img[:, :, 0] = np.clip(35 + val * 45, 0, 255)   # B
    img[:, :, 1] = np.clip(75 + val * 75, 0, 255)   # G
    img[:, :, 2] = np.clip(120 + val * 85, 0, 255)  # R
    img = cv2.GaussianBlur(img, (3, 3), 0)
    return img


def make_stone_texture() -> np.ndarray:
    img = make_noise_texture((120, 120, 115), 55, 9)
    rng = np.random.default_rng(21)
    for _ in range(24):
        pts = []
        x = int(rng.integers(0, TEXTURE_SIZE))
        y = int(rng.integers(0, TEXTURE_SIZE))
        for _ in range(4):
            pts.append((x, y))
            x += int(rng.integers(-28, 29))
            y += int(rng.integers(-28, 29))
            x = max(0, min(TEXTURE_SIZE - 1, x))
            y = max(0, min(TEXTURE_SIZE - 1, y))
        cv2.polylines(img, [np.array(pts, dtype=np.int32)], False, (70, 70, 70), 1, cv2.LINE_AA)
    return img


def make_sand_texture() -> np.ndarray:
    img = make_noise_texture((120, 190, 220), 28, 3)
    rng = np.random.default_rng(31)
    for _ in range(550):
        x = int(rng.integers(0, TEXTURE_SIZE))
        y = int(rng.integers(0, TEXTURE_SIZE))
        c = int(rng.integers(150, 235))
        cv2.circle(img, (x, y), 1, (c - 35, c - 8, c), -1, cv2.LINE_AA)
    return img


def make_water_texture() -> np.ndarray:
    y, x = np.mgrid[0:TEXTURE_SIZE, 0:TEXTURE_SIZE]
    waves = 0.5 + 0.5 * np.sin(x / 10.0 + np.sin(y / 18.0) * 2.0)
    waves2 = 0.5 + 0.5 * np.sin((x + y) / 22.0)
    val = 0.65 * waves + 0.35 * waves2
    img = np.zeros((TEXTURE_SIZE, TEXTURE_SIZE, 3), dtype=np.uint8)
    img[:, :, 0] = np.clip(140 + val * 100, 0, 255)
    img[:, :, 1] = np.clip(80 + val * 90, 0, 255)
    img[:, :, 2] = np.clip(20 + val * 55, 0, 255)
    return cv2.GaussianBlur(img, (5, 5), 0)


def make_glass_texture() -> np.ndarray:
    y, x = np.mgrid[0:TEXTURE_SIZE, 0:TEXTURE_SIZE]
    diagonal = 0.5 + 0.5 * np.sin((x + y) / 23.0)
    soft_wave = 0.5 + 0.5 * np.sin(x / 34.0 + np.sin(y / 40.0))
    val = 0.6 * diagonal + 0.4 * soft_wave

    img = np.zeros((TEXTURE_SIZE, TEXTURE_SIZE, 3), dtype=np.uint8)
    img[:, :, 0] = np.clip(185 + val * 55, 0, 255)   # B
    img[:, :, 1] = np.clip(205 + val * 45, 0, 255)   # G
    img[:, :, 2] = np.clip(215 + val * 35, 0, 255)   # R

    # Light reflection streaks.
    for offset in range(-TEXTURE_SIZE, TEXTURE_SIZE, 44):
        p1 = (max(0, offset), max(0, -offset))
        p2 = (min(TEXTURE_SIZE - 1, offset + TEXTURE_SIZE), min(TEXTURE_SIZE - 1, TEXTURE_SIZE - offset))
        cv2.line(img, p1, p2, (255, 255, 255), 2, cv2.LINE_AA)

    img = cv2.GaussianBlur(img, (5, 5), 0)
    return img


def make_metal_texture() -> np.ndarray:
    rng = np.random.default_rng(63)
    img = np.zeros((TEXTURE_SIZE, TEXTURE_SIZE, 3), dtype=np.uint8)

    base = np.linspace(95, 175, TEXTURE_SIZE, dtype=np.uint8)
    for y in range(TEXTURE_SIZE):
        shade = int(base[y])
        img[y, :, :] = (shade, shade, shade)

    noise = rng.normal(0, 18, img.shape).astype(np.int16)
    img = np.clip(img.astype(np.int16) + noise, 0, 255).astype(np.uint8)

    # Brushed metal horizontal streaks.
    for y in range(0, TEXTURE_SIZE, 5):
        c = int(rng.integers(115, 220))
        cv2.line(img, (0, y), (TEXTURE_SIZE, y + int(rng.integers(-1, 2))), (c, c, c), 1, cv2.LINE_AA)

    # Slight cool tint.
    img[:, :, 0] = np.clip(img[:, :, 0].astype(np.int16) + 18, 0, 255).astype(np.uint8)
    img = cv2.GaussianBlur(img, (7, 1), 0)
    return img


def make_leaf_texture() -> np.ndarray:
    img = make_noise_texture((35, 145, 70), 25, 5)
    center = (TEXTURE_SIZE // 2, TEXTURE_SIZE)
    cv2.line(img, center, (TEXTURE_SIZE // 2, 0), (120, 220, 120), 2, cv2.LINE_AA)
    for y in range(20, TEXTURE_SIZE, 24):
        cv2.line(img, (TEXTURE_SIZE // 2, y), (20, max(0, y - 30)), (95, 200, 105), 1, cv2.LINE_AA)
        cv2.line(img, (TEXTURE_SIZE // 2, y), (TEXTURE_SIZE - 20, max(0, y - 30)), (95, 200, 105), 1, cv2.LINE_AA)
    return img


def make_clay_texture() -> np.ndarray:
    img = make_noise_texture((80, 105, 170), 38, 7)
    rng = np.random.default_rng(88)
    for _ in range(35):
        x1 = int(rng.integers(0, TEXTURE_SIZE))
        y1 = int(rng.integers(0, TEXTURE_SIZE))
        x2 = x1 + int(rng.integers(-50, 51))
        y2 = y1 + int(rng.integers(-30, 31))
        cv2.line(img, (x1, y1), (x2, y2), (55, 75, 125), 1, cv2.LINE_AA)
    return img


def build_texture_library() -> Dict[str, np.ndarray]:
    library = {
        "Grass": make_grass_texture(),
        "Wood": make_wood_texture(),
        "Stone": make_stone_texture(),
        "Sand": make_sand_texture(),
        "Water": make_water_texture(),
        "Glass": make_glass_texture(),
        "Metal": make_metal_texture(),
        "Leaf": make_leaf_texture(),
        "Clay": make_clay_texture(),
    }

    # Optional: put your own .png/.jpg files in a folder named "textures" next to this script.
    texture_folder = Path("textures")
    if texture_folder.exists():
        for path in sorted(texture_folder.glob("*")):
            if path.suffix.lower() not in {".png", ".jpg", ".jpeg", ".webp"}:
                continue
            img = cv2.imread(str(path), cv2.IMREAD_COLOR)
            if img is None:
                continue
            img = cv2.resize(img, (TEXTURE_SIZE, TEXTURE_SIZE), interpolation=cv2.INTER_AREA)
            library[path.stem[:18]] = img

    return library


def draw_texture_on_polygon(frame: np.ndarray, polygon: np.ndarray, texture: np.ndarray, alpha: float) -> None:
    if texture is None:
        return

    tex_h, tex_w = texture.shape[:2]
    src_pts = np.array([[0, 0], [tex_w - 1, 0], [tex_w - 1, tex_h - 1], [0, tex_h - 1]], dtype=np.float32)
    dst_pts = polygon.astype(np.float32)

    H = cv2.getPerspectiveTransform(src_pts, dst_pts)
    warped = cv2.warpPerspective(
        texture,
        H,
        (frame.shape[1], frame.shape[0]),
        flags=cv2.INTER_LINEAR,
        borderMode=cv2.BORDER_CONSTANT,
    )

    mask = np.zeros(frame.shape[:2], dtype=np.uint8)
    cv2.fillPoly(mask, [polygon.astype(np.int32)], 255)
    mask_bool = mask > 0

    frame[mask_bool] = cv2.addWeighted(
        frame[mask_bool],
        1.0 - alpha,
        warped[mask_bool],
        alpha,
        0,
    )


def draw_texture_on_track(frame: np.ndarray, track: Track, texture_name: str, alpha: float) -> None:
    texture = texture_library.get(texture_name)
    if texture is None:
        return
    draw_texture_on_polygon(frame, plane_polygon(track), texture, alpha)


def draw_round_rect(img: np.ndarray, x: int, y: int, w: int, h: int, color: Tuple[int, int, int], radius: int = 12, thickness: int = -1) -> None:
    radius = max(0, min(radius, w // 2, h // 2))
    if thickness == -1:
        cv2.rectangle(img, (x + radius, y), (x + w - radius, y + h), color, -1)
        cv2.rectangle(img, (x, y + radius), (x + w, y + h - radius), color, -1)
        cv2.circle(img, (x + radius, y + radius), radius, color, -1)
        cv2.circle(img, (x + w - radius, y + radius), radius, color, -1)
        cv2.circle(img, (x + radius, y + h - radius), radius, color, -1)
        cv2.circle(img, (x + w - radius, y + h - radius), radius, color, -1)
    else:
        cv2.rectangle(img, (x + radius, y), (x + w - radius, y + h), color, thickness)
        cv2.rectangle(img, (x, y + radius), (x + w, y + h - radius), color, thickness)


def ui_text(img: np.ndarray, text: str, x: int, y: int, scale: float = 0.52, color: Tuple[int, int, int] = (235, 245, 255), thick: int = 1) -> None:
    cv2.putText(img, text, (x, y), cv2.FONT_HERSHEY_SIMPLEX, scale, color, thick, cv2.LINE_AA)


def add_ui_button(action: str, rect: Tuple[int, int, int, int], value: object = None) -> None:
    ui_buttons.append({"action": action, "rect": rect, "value": value})


def draw_button(panel: np.ndarray, x: int, y: int, w: int, h: int, label: str, action: str, value: object = None, active: bool = False) -> None:
    color = (58, 72, 98) if not active else (70, 135, 190)
    border = (105, 140, 190) if not active else (150, 220, 255)
    draw_round_rect(panel, x, y, w, h, color, 12, -1)
    cv2.rectangle(panel, (x + 2, y + 2), (x + w - 2, y + h - 2), border, 1, cv2.LINE_AA)
    ui_text(panel, label, x + 14, y + h // 2 + 6, 0.52, (245, 250, 255), 1)
    add_ui_button(action, (camera_view_width + x, y, w, h), value)


def load_embedded_logo(max_width: int = 150, max_height: int = 135) -> Optional[np.ndarray]:
    try:
        raw = base64.b64decode(EMBEDDED_LOGO_BASE64)
        arr = np.frombuffer(raw, dtype=np.uint8)
        logo = cv2.imdecode(arr, cv2.IMREAD_UNCHANGED)
        if logo is None:
            return None

        if logo.shape[2] == 4:
            # Composite transparent PNG on white, then convert to BGR.
            alpha = logo[:, :, 3:4].astype(np.float32) / 255.0
            bgr = logo[:, :, :3].astype(np.float32)
            white = np.full_like(bgr, 255.0)
            logo = (bgr * alpha + white * (1.0 - alpha)).astype(np.uint8)
        else:
            logo = logo[:, :, :3]

        h, w = logo.shape[:2]
        scale = min(max_width / max(1, w), max_height / max(1, h))
        new_w = max(1, int(w * scale))
        new_h = max(1, int(h * scale))
        return cv2.resize(logo, (new_w, new_h), interpolation=cv2.INTER_AREA)
    except Exception as exc:
        print(f"Could not load embedded logo: {exc}")
        return None


def paste_image(panel: np.ndarray, img: np.ndarray, x: int, y: int) -> None:
    if img is None:
        return
    h, w = img.shape[:2]
    y2 = min(panel.shape[0], y + h)
    x2 = min(panel.shape[1], x + w)
    if y2 <= y or x2 <= x:
        return
    panel[y:y2, x:x2] = img[:y2 - y, :x2 - x]


def add_slider(action: str, rect: Tuple[int, int, int, int], value: object = None) -> None:
    ui_buttons.append({"action": action, "rect": rect, "value": value})


def show_brush_preview(duration: float = 1.25) -> None:
    global brush_preview_until
    brush_preview_until = time.time() + duration


def set_brush_size_from_slider(global_x: int) -> None:
    global brush_size

    for item in ui_buttons:
        if item.get("action") != "brush_slider":
            continue

        bx, by, bw, bh = item["rect"]
        t = (global_x - bx) / max(1, bw)
        t = max(0.0, min(1.0, t))
        brush_size = int(round(2 + t * (52 - 2)))
        brush_size = max(2, min(52, brush_size))
        show_brush_preview()
        print(f"Brush size: {brush_size}")
        return


def draw_style_button(panel: np.ndarray, x: int, y: int, w: int, h: int, label: str, action: str, value: object = None, active: bool = False) -> None:
    # Build Your Case inspired: sharp, graphic, black/blue/lime.
    fill = (0, 0, 0) if active else (235, 232, 228)
    border = (152, 220, 0) if active else (20, 20, 20)
    text_col = (255, 255, 255) if active else (0, 0, 0)

    cv2.rectangle(panel, (x, y), (x + w, y + h), fill, -1)
    cv2.rectangle(panel, (x, y), (x + w, y + h), border, 2, cv2.LINE_AA)
    ui_text(panel, label, x + 12, y + h // 2 + 6, 0.48, text_col, 1)

    # small lime plus-like accent on active buttons
    if active:
        cx = x + w - 18
        cy = y + h // 2
        cv2.line(panel, (cx - 6, cy), (cx + 6, cy), (152, 220, 0), 2, cv2.LINE_AA)
        cv2.line(panel, (cx, cy - 6), (cx, cy + 6), (152, 220, 0), 2, cv2.LINE_AA)

    add_ui_button(action, (camera_view_width + x, y, w, h), value)


def draw_sidebar(camera_frame: np.ndarray, fps: float, detections: List[Detection]) -> np.ndarray:
    global ui_buttons

    h, w = camera_frame.shape[:2]
    panel = np.zeros((h, UI_PANEL_WIDTH, 3), dtype=np.uint8)
    panel[:] = (232, 229, 225)

    ui_buttons = []

    BLACK = (0, 0, 0)
    WHITE = (255, 255, 255)
    PAPER = (232, 229, 225)
    LIME = (152, 220, 0)
    GREY = (120, 120, 120)
    BLUE = (126, 154, 179)

    x = 22
    y = 16
    inner_w = UI_PANEL_WIDTH - 44

    # Compact header so all buttons fit in fullscreen/windowed mode.
    header_h = 84
    cv2.rectangle(panel, (x, y), (x + inner_w, y + header_h), BLACK, -1)
    ui_text(panel, "CONSTRAINT", x + 12, y + 17, 0.30, GREY, 1)
    ui_text(panel, "A-01", x + inner_w - 38, y + 17, 0.30, GREY, 1)
    ui_text(panel, "BUILD", x + 14, y + 48, 0.78, WHITE, 2)
    ui_text(panel, "YOUR CASE", x + 14, y + 78, 0.78, WHITE, 2)
    cx = x + inner_w - 24
    cy = y + 66
    cv2.line(panel, (cx - 7, cy), (cx + 7, cy), LIME, 2, cv2.LINE_AA)
    cv2.line(panel, (cx, cy - 7), (cx, cy + 7), LIME, 2, cv2.LINE_AA)

    y += header_h + 8

    # Compact logo/status card.
    logo_box_h = 54
    cv2.rectangle(panel, (x, y), (x + inner_w, y + logo_box_h), PAPER, -1)
    cv2.rectangle(panel, (x, y), (x + inner_w, y + logo_box_h), BLACK, 1, cv2.LINE_AA)

    logo = load_embedded_logo(max_width=40, max_height=40)
    if logo is not None:
        paste_image(panel, logo, x + 10, y + 7)

    active_label = "none" if active_key is None else f"ID {active_key[1]}"
    mode_label = "ERASER" if eraser_mode else "DRAW"
    ui_text(panel, "BUILD YOUR CASE", x + 62, y + 17, 0.34, GREY, 1)
    ui_text(panel, f"{mode_label} / FACE {active_label}", x + 62, y + 39, 0.48, BLACK, 1)

    for i in range(4):
        sx = x + inner_w - 18
        sy = y + 9 + i * 9
        cv2.line(panel, (sx, sy + 7), (sx + 8, sy), LIME, 3, cv2.LINE_AA)

    y += logo_box_h + 12

    # Materials.
    ui_text(panel, "MATERIALS", x, y, 0.56, BLACK, 2)
    ui_text(panel, "DRAG ONTO FACE", x + 126, y, 0.32, GREY, 1)
    y += 10

    swatch_w = 96
    swatch_h = 42
    gap = 11
    cols = 3
    texture_names = list(texture_library.keys())

    for i, name in enumerate(texture_names[:9]):
        col = i % cols
        row = i // cols
        sx = x + col * (swatch_w + gap)
        sy = y + 10 + row * (swatch_h + 24)

        tex = texture_library[name]
        thumb = cv2.resize(tex, (swatch_w, swatch_h), interpolation=cv2.INTER_AREA)
        panel[sy:sy + swatch_h, sx:sx + swatch_w] = thumb

        border = LIME if name == current_texture_name else BLACK
        cv2.rectangle(panel, (sx, sy), (sx + swatch_w, sy + swatch_h), border, 2, cv2.LINE_AA)
        cv2.rectangle(panel, (sx, sy + swatch_h - 16), (sx + swatch_w, sy + swatch_h), BLACK, -1)
        ui_text(panel, name.upper(), sx + 5, sy + swatch_h - 4, 0.30, WHITE, 1)

        if name == current_texture_name:
            cv2.rectangle(panel, (sx + swatch_w - 12, sy + 5), (sx + swatch_w - 5, sy + 12), LIME, -1)

        add_ui_button("select_texture", (camera_view_width + sx, sy, swatch_w, swatch_h), name)

    y += 3 * (swatch_h + 24) + 16

    draw_style_button(panel, x, y, 164, 32, "APPLY FACE", "apply_texture", None, False)
    draw_style_button(panel, x + 178, y, 164, 32, "REMOVE", "remove_texture", None, False)
    y += 42

    # Brush slider moved slightly lower and compacted to avoid collision.
    y += 6
    ui_text(panel, "BRUSH SIZE", x, y, 0.52, BLACK, 2)
    ui_text(panel, str(brush_size), x + inner_w - 30, y, 0.52, BLACK, 2)

    # Live preview circle in the UI.
    preview_cx = x + inner_w - 74
    preview_cy = y - 4
    preview_radius = max(2, min(26, brush_size // 2))
    cv2.circle(panel, (preview_cx, preview_cy), preview_radius, brush_color, -1, cv2.LINE_AA)
    cv2.circle(panel, (preview_cx, preview_cy), preview_radius, BLACK, 1, cv2.LINE_AA)

    y += 17
    slider_x = x
    slider_y = y
    slider_w = inner_w
    slider_h = 26
    cv2.rectangle(panel, (slider_x, slider_y + 10), (slider_x + slider_w, slider_y + 16), BLACK, -1)

    t = (brush_size - 2) / max(1, 52 - 2)
    knob_x = int(slider_x + t * slider_w)
    cv2.rectangle(panel, (slider_x, slider_y + 10), (knob_x, slider_y + 16), LIME, -1)
    cv2.circle(panel, (knob_x, slider_y + 13), 11, BLACK, -1, cv2.LINE_AA)
    cv2.circle(panel, (knob_x, slider_y + 13), 7, LIME, -1, cv2.LINE_AA)
    add_slider("brush_slider", (camera_view_width + slider_x, slider_y, slider_w, slider_h), None)
    y += 38

    # Color row.
    ui_text(panel, "DRAW COLOR", x, y, 0.52, BLACK, 2)
    y += 12

    for idx, (key_code, (color, name)) in enumerate(BRUSH_COLORS.items()):
        cx2 = x + (idx % 9) * 34
        cy2 = y + (idx // 9) * 31
        cv2.rectangle(panel, (cx2, cy2), (cx2 + 26, cy2 + 26), color, -1)
        border = LIME if brush_color == color and not eraser_mode else BLACK
        cv2.rectangle(panel, (cx2, cy2), (cx2 + 26, cy2 + 26), border, 2, cv2.LINE_AA)
        ui_text(panel, chr(key_code), cx2 + 9, cy2 + 18, 0.36, (0, 0, 0) if color != BLACK else WHITE, 1)
        add_ui_button("select_color", (camera_view_width + cx2, cy2, 26, 26), key_code)

    y += 42

    # Main controls. Undo is kept clearly visible.
    draw_style_button(panel, x, y, 104, 32, "DRAW", "draw_mode", None, not eraser_mode)
    draw_style_button(panel, x + 116, y, 104, 32, "ERASER", "eraser_mode", None, eraser_mode)
    draw_style_button(panel, x + 232, y, 104, 32, "UNDO", "undo", None, False)
    y += 42

    draw_style_button(panel, x, y, 164, 32, "CLEAR FACE", "clear_face", None, False)
    draw_style_button(panel, x + 178, y, 164, 32, "CLEAR ALL", "clear_all", None, False)
    y += 42

    # Bottom card only if there is enough space.
    if y + 76 < h:
        cv2.rectangle(panel, (x, y), (x + inner_w, y + 68), PAPER, -1)
        cv2.rectangle(panel, (x, y), (x + inner_w, y + 68), BLACK, 1, cv2.LINE_AA)
        ui_text(panel, "ONLY USE", x + 14, y + 21, 0.42, BLACK, 1)
        ui_text(panel, "THREE DIFFERENT TEXTURES", x + 14, y + 42, 0.42, BLACK, 1)
        ui_text(panel, "CHANGE THE CASE.", x + 14, y + 61, 0.32, LIME, 1)

    return np.hstack([camera_frame, panel])



def handle_ui_press(x: int, y: int) -> bool:
    global current_texture_name, brush_color, current_color_name, dragging_texture_name
    global eraser_mode, current_stroke, mouse_down, ui_drag_action

    for button in reversed(ui_buttons):
        bx, by, bw, bh = button["rect"]
        if bx <= x <= bx + bw and by <= y <= by + bh:
            action = str(button["action"])
            value = button.get("value")

            if action == "brush_slider":
                ui_drag_action = "brush_slider"
                set_brush_size_from_slider(x)
                mouse_down = False
                current_stroke = None
                reset_pending_first_point()
                return True

            if action == "select_texture" and isinstance(value, str):
                current_texture_name = value
                dragging_texture_name = value
                mouse_down = False
                current_stroke = None
                reset_pending_first_point()
                print(f"Dragging texture: {current_texture_name}")
                return True

            if action == "apply_texture":
                if active_key is not None:
                    apply_texture_to_key(active_key, current_texture_name, record=True)
                else:
                    print("Click one cube face first, then apply a material.")
                return True

            if action == "remove_texture":
                if active_key is not None:
                    remove_texture_from_key(active_key, record=True)
                return True

            if action == "select_color" and isinstance(value, int):
                if value in BRUSH_COLORS:
                    brush_color, current_color_name = BRUSH_COLORS[value]
                    eraser_mode = False
                    print(f"Brush color: {current_color_name}")
                return True

            if action == "clear_face":
                if active_key is not None:
                    clear_key(active_key, record=True)
                return True

            if action == "undo":
                undo_last_action()
                return True

            if action == "clear_all":
                clear_everything(record=True)
                return True

            if action == "draw_mode":
                eraser_mode = False
                print("Draw mode")
                return True

            if action == "eraser_mode":
                eraser_mode = True
                current_stroke = None
                reset_pending_first_point()
                print("Eraser mode")
                return True

    return False


def handle_texture_drop(x: int, y: int) -> bool:
    global dragging_texture_name, active_key

    if dragging_texture_name is None:
        return False

    if x < camera_view_width:
        drop_key = find_track_under_mouse(x, y, require_drawable=False)
        if drop_key is not None:
            active_key = drop_key
            apply_texture_to_key(drop_key, dragging_texture_name, record=True)
        else:
            print("Drop texture on a visible cube face.")

    dragging_texture_name = None
    return True





def cycle_texture(direction: int) -> None:
    global current_texture_name
    names = list(texture_library.keys())
    if not names:
        return
    if current_texture_name not in names:
        current_texture_name = names[0]
        return
    idx = names.index(current_texture_name)
    current_texture_name = names[(idx + direction) % len(names)]
    print(f"Selected texture: {current_texture_name}")


