# Drawing/rendering
# -----------------------------

def draw_alpha_polygon(frame: np.ndarray, polygon: np.ndarray, color: Tuple[int, int, int], alpha: float) -> None:
    overlay = frame.copy()
    cv2.fillPoly(overlay, [polygon], color)
    cv2.addWeighted(overlay, alpha, frame, 1 - alpha, 0, frame)


def draw_track(frame: np.ndarray, track: Track) -> None:
    key = track.key
    active = key == active_key
    missed = track.misses > 0

    plane_poly = plane_polygon(track)
    marker_poly = marker_polygon(track)

    default_plane_color = (255, 200, 80) if active else (255, 180, 40)
    plane_color = default_plane_color if not missed else (150, 150, 150)

    if key in textures_by_marker:
        draw_texture_on_track(frame, track, textures_by_marker[key], TEXTURE_ALPHA if not missed else 0.28)

    if key in fills_by_marker:
        fill_color, alpha = fills_by_marker[key]
        draw_alpha_polygon(frame, plane_poly, fill_color if not missed else (120, 120, 120), alpha if not missed else 0.12)
    elif SHOW_EMPTY_FACE_TINT and key not in textures_by_marker:
        draw_alpha_polygon(frame, plane_poly, plane_color, 0.12 if not missed else 0.07)

    outline_color = (255, 255, 255) if active else plane_color

    if SHOW_PLANE_OUTLINES:
        cv2.polylines(frame, [plane_poly], True, outline_color, 2 if not active else 3, cv2.LINE_AA)

    if SHOW_MARKER_OUTLINES:
        cv2.polylines(frame, [marker_poly], True, (255, 255, 255), 2, cv2.LINE_AA)

        label = f"ID {track.marker_id}"
        if DICTIONARY_NAME == "AUTO":
            label += f" | {track.dictionary_name.replace('DICT_', '')}"
        if missed:
            label += " HOLD"
        if active:
            label += " | ACTIVE"

        label_pos = tuple(np.round(track.corners[0]).astype(int))
        cv2.putText(frame, label, (label_pos[0], max(24, label_pos[1] - 10)), cv2.FONT_HERSHEY_SIMPLEX, 0.55, outline_color, 2, cv2.LINE_AA)

    strokes = strokes_by_marker.get(key, [])
    for stroke in strokes:
        if not stroke.points:
            continue
        pts = np.array([project_plane_point(track, u, v) for u, v in stroke.points], dtype=np.int32)
        if len(pts) == 1:
            cv2.circle(frame, tuple(pts[0]), max(1, stroke.size // 2), stroke.color, -1, cv2.LINE_AA)
        else:
            cv2.polylines(frame, [pts], False, stroke.color, stroke.size, cv2.LINE_AA)


def draw_palette(frame: np.ndarray, x0: int, y0: int) -> int:
    # Legacy function kept for compatibility. The new UI is the right sidebar.
    return y0


def draw_ui(frame: np.ndarray, fps: float, detections: List[Detection]) -> None:
    # Legacy function kept for compatibility. The new UI is added in render_frame.
    return



def render_frame(frame: np.ndarray, fps: float, detections: List[Detection]) -> np.ndarray:
    global camera_view_width

    output = frame.copy()
    camera_view_width = output.shape[1]

    tracks_sorted = sorted(visible_tracks(), key=lambda t: (t.key == active_key, polygon_area(t.corners)))
    for track in tracks_sorted:
        draw_track(output, track)

    # Texture drag preview: while dragging a texture, preview it on the face under the mouse.
    if dragging_texture_name is not None and mouse_pos[0] < camera_view_width:
        preview_key = find_track_under_mouse(mouse_pos[0], mouse_pos[1], require_drawable=False)
        if preview_key is not None and preview_key in tracks:
            draw_texture_on_track(output, tracks[preview_key], dragging_texture_name, 0.55)

    if eraser_mode and mouse_pos[0] < camera_view_width:
        cv2.circle(output, mouse_pos, eraser_size, (245, 245, 245), 2, cv2.LINE_AA)
        cv2.circle(output, mouse_pos, max(2, eraser_size // 4), (40, 40, 40), 1, cv2.LINE_AA)

    # Temporary live brush preview on the camera image when the size changes.
    if (not eraser_mode) and time.time() < brush_preview_until:
        px = min(max(78, mouse_pos[0]), max(78, camera_view_width - 78))
        py = min(max(78, mouse_pos[1]), max(78, output.shape[0] - 78))
        cv2.circle(output, (px, py), max(2, brush_size // 2), brush_color, -1, cv2.LINE_AA)
        cv2.circle(output, (px, py), max(2, brush_size // 2), (255, 255, 255), 2, cv2.LINE_AA)
        cv2.putText(output, f"Brush {brush_size}", (px - 46, py + max(38, brush_size // 2 + 28)),
                    cv2.FONT_HERSHEY_SIMPLEX, 0.55, (0, 0, 0), 4, cv2.LINE_AA)
        cv2.putText(output, f"Brush {brush_size}", (px - 46, py + max(38, brush_size // 2 + 28)),
                    cv2.FONT_HERSHEY_SIMPLEX, 0.55, (255, 255, 255), 1, cv2.LINE_AA)

    if show_ui:
        return draw_sidebar(output, fps, detections)

    return output



