def on_mouse(event, x, y, flags, param) -> None:
    global mouse_pos, mouse_down, current_stroke, active_key, ui_drag_action
    mouse_pos = (x, y)

    if ui_drag_action == "brush_slider":
        if event == cv2.EVENT_MOUSEMOVE:
            set_brush_size_from_slider(x)
        elif event == cv2.EVENT_LBUTTONUP:
            set_brush_size_from_slider(x)
            ui_drag_action = None
        return

    # Texture drag starts in the UI, then can be dropped onto the camera image.
    if dragging_texture_name is not None:
        if event == cv2.EVENT_LBUTTONUP:
            handle_texture_drop(x, y)
        return

    # Clicks in the right UI panel should not draw on the camera image.
    if show_ui and x >= camera_view_width:
        if event == cv2.EVENT_LBUTTONDOWN:
            handle_ui_press(x, y)
        mouse_down = False
        current_stroke = None
        reset_pending_first_point()
        return

    # Ignore anything outside the camera image.
    if x < 0 or x >= camera_view_width:
        return

    if event == cv2.EVENT_LBUTTONDOWN:
        mouse_down = True
        reset_pending_first_point()

        if eraser_mode:
            current_stroke = None
            erase_under_mouse(x, y)
            return

        selected_key = find_track_under_mouse(x, y)
        if selected_key is not None:
            active_key = selected_key
            current_stroke = None
            add_point_to_current_stroke(x, y)
        else:
            current_stroke = None

    elif event == cv2.EVENT_MOUSEMOVE:
        if mouse_down:
            if eraser_mode:
                erase_under_mouse(x, y)
            else:
                add_point_to_current_stroke(x, y)

    elif event == cv2.EVENT_LBUTTONUP:
        mouse_down = False
        current_stroke = None
        reset_pending_first_point()



def handle_key(key: int, current_frame: Optional[np.ndarray]) -> bool:
    global brush_color, brush_size, eraser_size, plane_scale, show_ui, locked_dictionary
    global dictionary_hit_counts, active_key, current_color_name, current_texture_name, eraser_mode, current_stroke, fullscreen_mode

    if key in (27, ord("q")):
        return False

    if key in BRUSH_COLORS:
        brush_color, current_color_name = BRUSH_COLORS[key]
        eraser_mode = False
        print(f"Brush color: {current_color_name}")

    elif key in (ord("n"), 9):
        cycle_texture(1)

    elif key == ord("b"):
        cycle_texture(-1)

    elif key == ord("t"):
        if active_key is not None:
            apply_texture_to_key(active_key, current_texture_name, record=True)
        else:
            print("Click one cube face first, then press t to apply the material.")

    elif key == ord("y"):
        if active_key is not None:
            remove_texture_from_key(active_key, record=True)

    elif key == ord("e"):
        eraser_mode = True
        current_stroke = None
        reset_pending_first_point()
        print("Eraser mode")

    elif key == ord("p"):
        eraser_mode = False
        reset_pending_first_point()
        print("Draw mode")

    elif key == ord("["):
        if eraser_mode:
            eraser_size = max(4, eraser_size - 2)
            print(f"Eraser size: {eraser_size}")
        else:
            brush_size = max(2, brush_size - 1)
            show_brush_preview()
            print(f"Brush size: {brush_size}")

    elif key == ord("]"):
        if eraser_mode:
            eraser_size = min(90, eraser_size + 2)
            print(f"Eraser size: {eraser_size}")
        else:
            brush_size = min(52, brush_size + 1)
            show_brush_preview()
            print(f"Brush size: {brush_size}")

    elif key in (ord("+"), ord("=")):
        plane_scale = min(2.50, plane_scale + 0.05)
        print(f"Plane scale: {plane_scale:.2f}")

    elif key in (ord("-"), ord("_")):
        plane_scale = max(0.60, plane_scale - 0.05)
        print(f"Plane scale: {plane_scale:.2f}")

    elif key == ord("f"):
        if active_key is not None:
            apply_texture_to_key(active_key, current_texture_name, record=True)
        else:
            print("Click one cube face first, then press f to apply the selected material.")

    elif key == ord("g"):
        if active_key is not None and active_key in fills_by_marker:
            fills_by_marker.pop(active_key, None)
            print(f"Removed fill for marker {active_key}")
        else:
            print("No fill to remove on the active marker.")

    elif key == ord("u"):
        undo_last_action()

    elif key == ord("c"):
        if active_key is not None:
            clear_key(active_key, record=True)
        else:
            print("No active marker selected. Click a plane first, or press x to clear all.")

    elif key == ord("x"):
        clear_everything(record=True)

    elif key in (ord("h"), ord("d")):
        show_ui = not show_ui
        print(f"UI text: {show_ui}")

    elif key == ord("m"):
        fullscreen_mode = not fullscreen_mode
        if fullscreen_mode:
            cv2.setWindowProperty(WINDOW_NAME, cv2.WND_PROP_FULLSCREEN, cv2.WINDOW_FULLSCREEN)
            print("Fullscreen on")
        else:
            cv2.setWindowProperty(WINDOW_NAME, cv2.WND_PROP_FULLSCREEN, cv2.WINDOW_NORMAL)
            cv2.resizeWindow(WINDOW_NAME, CAMERA_WIDTH + (UI_PANEL_WIDTH if show_ui else 0), CAMERA_HEIGHT)
            print("Fullscreen off")

    elif key == ord("r"):
        locked_dictionary = None
        dictionary_hit_counts = {}
        tracks.clear()
        active_key = None
        reset_pending_first_point()
        print("Reset dictionary lock and tracks")

    elif key == ord("s") and current_frame is not None:
        screenshots = Path("screenshots")
        screenshots.mkdir(exist_ok=True)
        filename = screenshots / f"aruco_cube_paint_{int(time.time())}.png"
        cv2.imwrite(str(filename), current_frame)
        print(f"Saved screenshot: {filename}")

    return True



