# Camera helpers
# -----------------------------

def enable_performance_mode() -> None:
    """Use more laptop resources for smoother camera + AR rendering.

    This keeps the ArUco detection logic unchanged.
    """
    try:
        cv2.setUseOptimized(True)
    except Exception:
        pass

    try:
        cpu_count = os.cpu_count() or 4
        cv2.setNumThreads(max(2, cpu_count - 1))
        print(f"OpenCV threads: {max(2, cpu_count - 1)}")
    except Exception:
        pass

    # Windows high-priority process mode. Built-in only; no extra libraries needed.
    try:
        if os.name == "nt":
            import ctypes
            HIGH_PRIORITY_CLASS = 0x00000080
            ctypes.windll.kernel32.SetPriorityClass(
                ctypes.windll.kernel32.GetCurrentProcess(),
                HIGH_PRIORITY_CLASS
            )
            print("Windows performance mode: high priority")
    except Exception:
        print("Windows performance mode: normal priority")


def camera_fps_is_auto() -> bool:
    return isinstance(CAMERA_FPS, str) and CAMERA_FPS.upper() == "AUTO"


def open_camera(index: int, fps_override: Optional[int] = None):
    """Open a camera with Logitech-friendly settings.

    When fps_override is None and CAMERA_FPS is AUTO, this opens at 30 fps for fast scanning.
    The selected camera is later reopened with open_camera_best_fps().
    """
    index = int(index)

    if fps_override is not None:
        fps_to_use = int(fps_override)
    elif camera_fps_is_auto():
        fps_to_use = 30
    else:
        fps_to_use = int(CAMERA_FPS)

    backends = []
    if hasattr(cv2, "CAP_DSHOW"):
        backends.append(cv2.CAP_DSHOW)
    backends.append(cv2.CAP_ANY)

    for backend in backends:
        cap = cv2.VideoCapture(index, backend)

        if cap is not None and cap.isOpened():
            try:
                # MJPG is important for many Logitech webcams at 720p/60.
                cap.set(cv2.CAP_PROP_FOURCC, cv2.VideoWriter_fourcc(*"MJPG"))
            except Exception:
                pass

            cap.set(cv2.CAP_PROP_FRAME_WIDTH, CAMERA_WIDTH)
            cap.set(cv2.CAP_PROP_FRAME_HEIGHT, CAMERA_HEIGHT)
            cap.set(cv2.CAP_PROP_FPS, fps_to_use)

            # Lower latency. This can help responsiveness without touching detection.
            if hasattr(cv2, "CAP_PROP_BUFFERSIZE"):
                cap.set(cv2.CAP_PROP_BUFFERSIZE, 1)

            # Warm-up exposure/focus a little.
            for _ in range(8):
                cap.read()

            return cap

        if cap is not None:
            cap.release()

    return cv2.VideoCapture(index)


def camera_reads_frames(cap) -> bool:
    if cap is None or not cap.isOpened():
        return False

    for _ in range(8):
        ok, frame = cap.read()
        if ok and frame is not None and frame.size > 0:
            return True

    return False


def measure_camera_fps(cap, frames: int = FPS_TEST_FRAMES) -> float:
    """Measure rough real camera FPS after settings are applied."""
    if cap is None or not cap.isOpened():
        return 0.0

    start = time.time()
    good = 0

    for _ in range(frames):
        ok, frame = cap.read()
        if ok and frame is not None and frame.size > 0:
            good += 1

    elapsed = max(0.001, time.time() - start)
    return good / elapsed


def open_camera_best_fps(index: int):
    """Try 60 fps first, but only keep it if it is actually faster.

    If 60 fps causes slow detection or webcam lag, this falls back to 30 fps.
    """
    if not camera_fps_is_auto():
        return open_camera(index, int(CAMERA_FPS))

    best_cap = None
    best_measured = 0.0
    best_requested = None

    for requested_fps in CAMERA_FPS_OPTIONS:
        cap = open_camera(index, requested_fps)

        if not camera_reads_frames(cap):
            if cap is not None:
                cap.release()
            continue

        measured = measure_camera_fps(cap)
        print(f"Camera {index}: requested {requested_fps} fps -> measured about {measured:.1f} fps")

        # If 60 is really working, keep it immediately.
        if requested_fps >= 50 and measured >= MIN_ACCEPTED_60_FPS:
            if best_cap is not None:
                best_cap.release()
            print("Using 60 fps camera mode")
            return cap

        # Otherwise keep the best measured option.
        if measured > best_measured:
            if best_cap is not None:
                best_cap.release()
            best_cap = cap
            best_measured = measured
            best_requested = requested_fps
        else:
            cap.release()

    if best_cap is not None:
        print(f"Using best available camera mode: requested {best_requested} fps, measured {best_measured:.1f} fps")
        return best_cap

    return open_camera(index, 30)


def scan_available_cameras() -> List[int]:
    found: List[int] = []

    print("Scanning cameras...")

    for index in range(CAMERA_SCAN_MAX_INDEX + 1):
        cap = open_camera(index)
        working = camera_reads_frames(cap)

        if working:
            found.append(index)
            print(f"  Camera {index}: works")
        else:
            print(f"  Camera {index}: not available")

        if cap is not None:
            cap.release()

    return found


def choose_camera_index(available: List[int]) -> int:
    if isinstance(CAMERA_INDEX, int):
        return int(CAMERA_INDEX)

    if isinstance(CAMERA_INDEX, str) and CAMERA_INDEX.upper().startswith("AUTO"):
        if not available:
            return 0

        # Usually: 0 = laptop webcam, 1/2 = external webcam.
        if PREFER_EXTERNAL_CAMERA and len(available) > 1:
            return available[-1]

        return available[0]

    try:
        return int(CAMERA_INDEX)
    except Exception:
        return 0


def next_camera_index(available: List[int], current_index: int) -> int:
    if not available:
        return current_index

    if current_index not in available:
        return available[0]

    pos = available.index(current_index)
    return available[(pos + 1) % len(available)]


def describe_camera(cap, index: int) -> None:
    width = int(cap.get(cv2.CAP_PROP_FRAME_WIDTH)) if cap is not None else 0
    height = int(cap.get(cv2.CAP_PROP_FRAME_HEIGHT)) if cap is not None else 0
    fps = cap.get(cv2.CAP_PROP_FPS) if cap is not None else 0

    print(f"Using camera {index} | {width}x{height} | camera reports {fps:.1f} fps")
    print("Press v to switch camera if this is not the right webcam.")
    print("Press m for fullscreen.")

# -----------------------------
# Main
# -----------------------------

def main() -> None:
    require_aruco()

    print("Starting Build Your Case - camera 1 fast startup")
    print("Original working ArUco detection, fixed to Logitech camera 1 at 30 fps.")
    print("No camera scan and no 60-fps test, so startup is faster.")

    global texture_library, current_texture_name

    texture_library = build_texture_library()
    if texture_library and current_texture_name not in texture_library:
        current_texture_name = next(iter(texture_library))

    detectors = build_detectors()

    # Fast startup: use camera 1 directly, no camera scan and no 60-fps test.
    available_cameras = [int(CAMERA_INDEX)]
    selected_camera_index = int(CAMERA_INDEX)

    cap = open_camera(selected_camera_index, CAMERA_FPS)

    if not camera_reads_frames(cap):
        raise RuntimeError(
            f"Could not open camera {selected_camera_index}. "
            "Your Logitech is expected on camera 1. If needed, change CAMERA_INDEX to 0 or 2 at the top of the file."
        )

    describe_camera(cap, selected_camera_index)

    cv2.namedWindow(WINDOW_NAME, cv2.WINDOW_NORMAL)
    cv2.resizeWindow(WINDOW_NAME, CAMERA_WIDTH + (UI_PANEL_WIDTH if show_ui else 0), CAMERA_HEIGHT)
    cv2.setMouseCallback(WINDOW_NAME, on_mouse)

    frame_index = 0
    fps = 0.0
    last_time = time.time()

    global last_frame_for_screenshot, active_key

    while True:
        ok, frame = cap.read()
        if not ok:
            print("Could not read frame from camera.")
            break

        frame_index += 1

        detections = detect_markers(frame, detectors)
        update_tracks(detections, frame_index)

        if active_key not in tracks and visible_tracks():
            active_key = max(visible_tracks(), key=lambda t: polygon_area(t.corners)).key

        now = time.time()
        dt = now - last_time
        last_time = now
        if dt > 0:
            fps = 0.90 * fps + 0.10 * (1.0 / dt) if fps > 0 else (1.0 / dt)

        output = render_frame(frame, fps, detections)
        last_frame_for_screenshot = output
        cv2.imshow(WINDOW_NAME, output)

        key = cv2.waitKey(1) & 0xFF
        if key != 255:
            if key == ord("v"):
                if not available_cameras:
                    available_cameras = scan_available_cameras()

                next_index = next_camera_index(available_cameras, selected_camera_index)
                print(f"Switching camera {selected_camera_index} -> {next_index}...")

                new_cap = open_camera(next_index, CAMERA_FPS)

                if camera_reads_frames(new_cap):
                    cap.release()
                    cap = new_cap
                    selected_camera_index = next_index
                    tracks.clear()
                    active_key = None
                    reset_pending_first_point()
                    describe_camera(cap, selected_camera_index)
                else:
                    if new_cap is not None:
                        new_cap.release()
                    print(f"Camera {next_index} could not be opened.")

            elif not handle_key(key, last_frame_for_screenshot):
                break

    cap.release()
    cv2.destroyAllWindows()


if __name__ == "__main__":
    try:
        main()
    except Exception as exc:
        print("\nERROR:")
        print(exc)
        print("\nCommon fix:")
        print("python -m pip uninstall opencv-python opencv-contrib-python -y")
        print("python -m pip install opencv-contrib-python numpy")
        raise
